INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0603553N$$, 2026, $$Effective FY 2026, Project 1704 moves from PE 0603553N to PE 0603561N as part of the PE/BLI consolidation effort in the DoD Implementation Plan from the
Commission on Planning, Programming, Budgeting, and Execution (PPBE) Reform Final Report in an effort to rapidly increase Navy Lethality in the Submarine and
Surface Fleet.

The objective of this Program Element (PE) is to pursue the development of technologies with the goal of improving Anti-Submarine Warfare (ASW) effectiveness to
the point of rendering the enemy submarine irrelevant against U.S. and coalition forces. U.S. adversaries continue to develop asymmetric capabilities and capacities
to deter, disrupt, or delay the entry of U.S. and allied naval forces, and pose a constant challenge as we implement the Maritime Strategy. These trends increase the
threats to U.S. surface combatants, thus requiring a focused effort to identify the most promising ASW technologies through a process of discovery, assessment,
experimentation, and analysis. Studies, experiments, and/or technology developments under this PE will seek to improve the ability of surface combatants to detect,
classify, localize, and track submerged contacts and detect and defend against modern torpedoes. To achieve these objectives, it is essential to develop new ASW
technologies. The products from these efforts will be provided to the Advanced Capability Build (ACB) program supporting the continuing improvement of the AN/
SQQ-89A(V)15 Surface Ship ASW Combat System.$$, $$The objective of this Project is to pursue the development of technologies with the goal of improving ASW effectiveness to the point of rendering the enemy submarine
irrelevant against U.S. and coalition forces. U.S. adversaries continue to develop asymmetric capabilities and capacities to deter, disrupt, or delay the entry of U.S. and
allied naval forces, and pose a constant challenge as we implement the Maritime Strategy. These trends increase the threats to U.S. surface combatants, thus requiring
a focused effort to identify the most promising ASW technologies through a process of discovery, assessment, experimentation, and analysis. Studies, experiments, and/
or technology developments under this PE will seek to improve the ability of surface combatants to detect, classify, localize, and track submerged contacts and detect
and defend against modern torpedoes. To achieve these objectives, it is essential to develop new ASW technologies. The products from these efforts will be provided to
the ACB program supporting the continuing improvement of the AN/SQQ-89A(V)15 Surface Ship ASW Combat System.

