INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0603635M$$, 2026, $$This PE supports the demonstration and validation of Marine Corps Ground/Supporting Arms Systems for utilization in Marine Air-Ground Expeditionary Force
amphibious operations. This program is funded under Demonstration and Validation because it develops and integrates hardware for experimental tests related to
specific ground weapon systems.$$, $$Long Range Unmanned Surface Vessel (LRUSV) is a Marine Corps Force Design priority that has demonstrated, through extensive wargaming and simulations,
significant operational impact in the Naval Expeditionary Force's surface warfare campaign against peer competitors in the maritime battlespace, particularly when
operating within planned sensor and communication networks. LRUSV is a semi-autonomous platform capable of multi-domain sensor collections that enables the
Marine Division / Marine Expeditionary Force to enhance Maritime Domain Awareness (MDA) for the Naval Expeditionary Force and Coalition maritime operations
centers. LRUSV will employ a suite of organic sensors (RADAR, EO/IR, and Electromagnetic Support) to accomplish its primary mission of gaining and maintaining
custody of surface contacts of interest in the littoral operating environment. LRUSV sensor capabilities will assist the Marine Division's Marine Reconnaissance Company
in its mission to conduct seaward reconnaissance, surveillance, and target acquisition in a peer-threat contested, littoral operating environment across the spectrum of
competition, crisis, and conflict to enhance Joint and coalition maritime domain awareness and facilitate the application of Joint fires.

In FY 2025, LRUSV continued autonomy software development and sensor integration activities and conducted testing of the manned/unmanned teaming concepts and
sea-based command and control (C2). In FY 2026, LRUSV will implement sensor enhancements, complete small form factor testing, and begin facilities studies.

