$$, $$5a24c4a5ceecdcf07fe90f7afe3a2d938652b282db934975f51bc40ab071d1ec$$, $${"A": "352723212e7d713a1739f0ceecd1d31a7726dc134600055f556cf764c172cc66", "D": "50eadd1516a11881d33f40e7ad71da35e34df2aa5af48b88aeaf88ba5d16f02d", "E": "8ee50e27a901329fcabad9c91ba17a5bbdf722feb33c268a2149a5092f676197"}$$::jsonb, $$Budget J-Books/FY26/USAF/FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, 465, $$2026-05-07T23:57:02.622579+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0604654N$$, 2027, $$This program, aligned with the National Defense Strategy, provides Joint Service Explosive Ordnance Disposal (EOD) and the supported Combatant Commanders with
information superiority by providing for the development of Unexploded Explosive Ordnance (UXO), Improvised Explosive Devices (IED), Weapons of Mass Destruction
(WMD), and weapons
systems Technical Manuals (TMs). TMs, which provide key identification features, hazardous materials, and safety information, are paramount to the success of EOD
Mission to detect, locate, access, identify, Render Safe/Neutralize, and dispose or recover both foreign and domestic explosive threats that pose a threat to military
operations, installations, personnel, and materials.

In addition, EOD Render Safe Procedures (RSP) and Disposal Procedures must be developed prior to fielding in the case of U.S. weapons and ordnance and as soon
as possible after gaining knowledge of existence as it pertains to foreign ordnance and other explosive threats. These efforts require collection, exploitation, and analysis
of the ordnance items and associated components, e.g., fuzing, prior to the development of EOD procedures.

As defined in DOD Directive 5160.62, assigns the Secretary of the Navy (SECNAV) the responsibility of Executive Agent for Explosive Ordnance Disposal (EOD)
Technology and Training (T&T). The Executive Agent for EOD T&T is to provide for the preparation, technical development, validation, Joint Service approval, and
distribution of all EOD procedures
and countermeasures to include; publications, manuals, bulletins, texts, and graphic aids. This program is a non-acquisition program (without traditional acquisition
milestones) with ongoing, continuous delivery of urgent and periodic documented procedures and publications for mines, ordnance items, weapons systems, Improvised
Explosive Devices, Weapons of Mass Destruction, and related explosive hazards.$$, $$This program, aligned with the National Defense Strategy, provides Joint Service Explosive Ordnance Disposal (EOD) and the supported Combatant Commanders with
information superiority by providing for the development of Unexploded Explosive Ordnance (UXO), Improvised Explosive Devices (IED), Weapons of Mass Destruction
(WMD), and weapons
systems Technical Manuals (TMs). TMs, which provide key identification features, hazardous materials, and safety information, are paramount to the success of EOD
Mission to detect, locate, access, identify, Render Safe/Neutralize, and dispose or recover both foreign and domestic explosive threats that pose a threat to military
operations, installations, personnel, and materials.

In addition, EOD Render Safe Procedures (RSP) and Disposal Procedures must be developed prior to fielding in the case of U.S. weapons and ordnance and as soon
as possible after gaining knowledge of existence as it pertains to foreign ordnance and other explosive threats. These efforts require collection, exploitation, and analysis
of the ordnance items and associated components, e.g., fuzing, prior to the development of EOD procedures.

As defined in DOD Directive 5160.62, assigns the Secretary of the Navy (SECNAV) the responsibility of Executive Agent for Explosive Ordnance Disposal (EOD)
Technology and Training (T&T). The Executive Agent for EOD T&T is to provide for the preparation, technical development, validation, Joint Service approval, and
distribution of all EOD procedures
and countermeasures to include; publications, manuals, bulletins, texts, and graphic aids. This program is a non-acquisition program (without traditional acquisition
milestones) with ongoing, continuous delivery of urgent and periodic documented procedures and publications for mines, ordnance items, weapons systems, Improvised
