INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0604727N$$, 2027, $$The Joint Standoff Weapon (JSOW) is an air-to-ground weapon designed to attack a variety of targets during day, night, and adverse weather conditions. JSOW
enhances aircraft survivability by providing the capability for launch aircraft to standoff outside the range of most target area surface-to-air threat systems. The JSOW
launch-and-leave capability will allow several target kills per aircraft sortie. The JSOW program first developed a baseline weapon for use against fixed area targets.
JSOW is a Navy led joint Navy/Air Force program. JSOW utilizes a "common truck" for both AGM-154A and AGM-154C variants. Through adherence to international
standards for weapons interfaces, weight, and dimension considerations, JSOW is compatible with Air Force and North Atlantic Treaty Organization aircraft.$$, $$The Joint Standoff Weapon (JSOW) is an air-to-ground weapon designed to attack a variety of targets during day, night, and adverse weather conditions. JSOW
enhances aircraft survivability by providing the capability for launch aircraft to standoff outside the range of most target area surface-to-air threat systems. The JSOW
launch-and-leave capability will allow several target kills per aircraft sortie. The JSOW program first developed a baseline weapon for use against fixed area targets.
JSOW is a Navy led joint Navy/Air Force program. JSOW utilizes a "common truck" for both AGM-154A and AGM-154C variants. Through adherence to international
standards for weapons interfaces, weight, and dimension considerations, JSOW is compatible with Air Force and North Atlantic Treaty Organization aircraft.

