INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605450M$$, 2027, $$The Joint Air-to-Ground Missile (JAGM) is an air-launched missile system that utilizes dual-mode seeker technology thus providing advanced line-of-sight and beyond-
line-of-sight capabilities, including precision point and fire-and-forget seeker targeting and increased lethality against soft, hardened, moving, stationary, land, maritime
threats. JAGM provides robust capability in adverse weather, day or night and in obscured/countermeasure environments. The JAGM Increment 1 system will replace
aviation-launched; tube-launched, optically-tracked, wire-guided (TOW), and Helicopter Launched Fire-&-Forget Missile (HELLFIRE) Systems. Later increments
of JAGM will be fixed wing compatible. JAGM is an Army-led joint program that addresses rotary wing, fixed wing and unmanned aerial vehicle requirements. The
Department of Navy threshold platform is the AH-1Z. The JAGM system includes the missile, trainers, containers, support equipment, M299 Launcher, and system
software modification.$$, $$The Joint Air-to-Ground Missile (JAGM) is an air-launched missile system that utilizes dual-mode seeker technology thus providing advanced line-of-sight and beyond-
line-of-sight capabilities, including precision point and fire-and-forget seeker targeting and increased lethality against soft, hardened, moving, stationary, land, maritime
threats. JAGM provides robust capability in adverse weather, day or night and in obscured/countermeasure environments. The JAGM Increment 1 system will replace
aviation-launched; tube-launched, optically-tracked, wire-guided (TOW), and Helicopter Launched Fire-&-Forget Missile (HELLFIRE) Systems. Later increments
of JAGM will be fixed wing compatible. JAGM is an Army-led joint program that addresses rotary wing, fixed wing and unmanned aerial vehicle requirements. The
Department of Navy threshold platform is the AH-1Z. The JAGM system includes the missile, trainers, containers, support equipment, M299 Launcher, and system
software modification.

